isEqual.isEqual:
(SELECT DISTINCT A.boardid BoardID, A.boardname BoardName, CASE WHEN (A.boardname2 = '' OR A.boardname2 IS NULL) THEN A.boardname ELSE A.boardname2 END BoardName2, CASE WHEN (A.boardname3 = '' OR A.boardname3 IS NULL) THEN A.boardname ELSE A.boardname3 END BoardName3, CASE WHEN (A.boardname4 = '' OR A.boardname4 IS NULL) THEN A.boardname ELSE A.boardname4 END BoardName4, A.treevieworder TreeViewOrder, A.boardcolor BoardColor, A.gubun, A.url, '' BoardGroupACL, A.USEGROUPFLAG FROM TBL_Board_BoardInfo A JOIN ( SELECT boardid , accessid , access_, tenant_id FROM TBL_Board_BoardManage WHERE TENANT_ID = #v_TENANTID# AND parentboardid = #v_pRootBoardID# AND access_ = 1 AND write_fg = 'true' AND boardid <> #v_pExcludeBoardID# AND accessid = #v_pUserID#
AND BoardGroupACL = 'Y'
) B ON A.TENANT_ID = B.TENANT_ID AND A.boardid = B.boardid WHERE A.TENANT_ID = #v_TENANTID# AND (A.companyid = #v_COMPANYID# OR TRIM(A.companyid) = '' OR A.companyid IS NULL) ) ORDER BY A.TreeViewOrder ASC

sqlMap.insert:
		INSERT INTO TBL_Board_BoardManage (
			BOARDID, ACCESSID, ACCESSNAME, ACCESSNAME2, ACCESSLEVEL, ACCESS_, PARENTBOARDID, BOARDADMIN_FG, LISTVIEW_FG, READ_FG, WRITE_FG, REPLY_FG, DELETE_FG, INHERIT_FG, POSTNOTICE, BOARDGROUPACL, TENANT_ID, COMPANYID, TYPE
		)
        VALUES ( 
        	#v_pBoardID#, #v_pAccessID#, #v_PACCESSNAME#, #v_PACCESSNAME2#, NULL,#v_PACCESSLEVEL#, #v_PACCESS#, #v_PPARENTBOARDID#, #v_PBOARDADMIN_FG#, #v_PLISTVIEW_FG#, #v_PREAD_FG#, #v_PWRITE_FG#, #v_PREPLY_FG#, #v_PDELETE_FG#, #v_PINHERIT_FG#, #v_PPOSTNOTICE#, #v_PBOARDGROUPACL#, #v_TENANTID#, #v_COMPANYID#, #v_TYPE# 
        )


			INSERT INTO TBL_Board_ApprList ( 
				BOARDID, APPRUSERID, TENANT_ID 
			)
          	VALUES ( 
          		#v_pBoardID#, #v_pAPPRUSERID#, #v_TENANTID# 
          	)


INSERT INTO	TBL_BOARD_BOARDINFO_ATTRIBUTE(
	boardid, 	tablecol, 		sn, 	colname1,	 	colname2, 		value, 		coltype, 	must,   tenant_id
)
VALUES(
	#boardID#, 	#tableCol#, 	#sn#, 	#colName1#,	 	#colName2#, 	#value#, 	#colType#, 	#must#, #tenantID#
)


			INSERT INTO TBL_Board_BoardManage ( 
				BoardID, 	  AccessID, 	 AccessName, 	  AccessName2, 		ACCESS_, 	 ParentBoardID, 	 BoardAdmin_FG, ListView_FG,   Read_FG,   Write_FG,   Reply_FG,   Delete_FG,   inherit_FG,   PostNotice, 	  BoardGroupACL, 	  tenant_id,  companyID, TYPE
			)
        	VALUES ( 
        		#v_pBoardID#, #v_pAccessID#, #v_pAccessName#, #v_pAccessName2#, #v_pAccess#, #v_pParentBoardID#, #v_pAdmin#, 	#v_pListView#, #v_pRead#, #v_pWrite#, #v_pReply#, #v_pDelete#, #v_pInherit#, #v_pPostNotice#, #v_pBoardGroupACL#, #v_TENANTID#, #v_COMPANYID#, #v_pType# 
        	)


			INSERT INTO TBL_Board_BoardBackGroundInfo ( 
				BACKGROUNDID, ORGFILENAME, SAVEFILENAME, REGUSERID, REGDATE, ISUSE, SN, WIDTH, HEIGHT, TENANT_ID, COMPANYID
			)
           	VALUES ( 
           		#v_BACKGROUNDID#, #v_ORGFILENAME#, #v_SAVEFILENAME#, #v_REGUSERID#, #v_REGDATE#, CASE WHEN (select 0 from dual where 8 < (SELECT COUNT(*) FROM TBL_Board_BoardBackGroundInfo A WHERE TENANT_ID = #v_TENANTID# AND ISUSE = '1')) IS NULL THEN 1 ELSE (select 0 from dual where 8 < (SELECT COUNT(*) FROM TBL_Board_BoardBackGroundInfo A WHERE TENANT_ID = #v_TENANTID# AND ISUSE = '1')) END, ( SELECT MAX(SN) FROM TBL_Board_BoardBackGroundInfo A WHERE TENANT_ID = #v_TENANTID# ) + 1, #v_WIDTH#, #v_HEIGHT#, #v_TENANTID#, #v_COMPANYID# 
           	)


			INSERT INTO TBL_Board_DeleteReservedBoard( 
				BoardID, 	  TENANT_ID
			)
      		VALUES ( 
      			#v_pBoardID#, #v_TENANTID# 
      		)


			INSERT INTO TBL_Board_MyTree ( 
				TREEID, USERID, TREENAME, TREENAME2, TREENAME3, TREENAME4, TREESTEP, TREEUPPER, TREEBOARDID, TENANT_ID, COMPANYID
			)
            VALUES ( 
            	#treeId#, #userId#, #treeName#, #treeName2#, #treeName3#, #treeName4#, ( SELECT CASE WHEN MAX(TREESTEP) IS NULL THEN 1 ELSE MAX(TREESTEP) + 1 END FROM TBL_Board_MyTree A WHERE TENANT_ID = #tenantID# AND TREEUPPER = #treeUpper# ), #treeUpper#, #boardId#, #tenantID#, #companyID# 
            )

insert.isEqual:

			INSERT INTO TBL_Board_TreeCache ( 
				QUERY, 		RESULT, 	TENANT_ID 
			)
        	VALUES (
        		#v_PQUERY#, #v_RESULT#, #v_TENANTID# 
        	)


			INSERT INTO TBL_Board_TreeCache ( 
				QUERY, 		RESULT2, 	TENANT_ID 
			)
        	VALUES (
        		#v_PQUERY#, #v_RESULT#, #v_TENANTID# 
        	)


			INSERT INTO TBL_Board_TreeCache ( 
				QUERY, 		RESULT3 , 	TENANT_ID 
			)
        	VALUES ( 
        		#v_PQUERY#, #v_RESULT#, #v_TENANTID#
        	)


			INSERT INTO TBL_Board_TreeCache ( 
				QUERY, 		RESULT4 , 	TENANT_ID 
			)
        	VALUES ( 
        		#v_PQUERY#, #v_RESULT#, #v_TENANTID#
        	)


			INSERT INTO TBL_Board_BoardInfo ( 
				BOARDID, BOARDNAME, BOARDNAME2, BOARDNAME3, BOARDNAME4, TREEVIEWORDER, PARENTBOARDID, GUBUN, BOARDNO, TENANT_ID
			)
     		VALUES ( 
     			#v_BOARDGROUPID#, #v_BOARDGROUPNAME#, #v_BOARDGROUPNAME2#, #v_BOARDGROUPNAME3#, #v_BOARDGROUPNAME4#, ( SELECT CASE WHEN MAX(TREEVIEWORDER) IS NULL THEN 1 ELSE MAX(TREEVIEWORDER) + 1 END FROM TBL_Board_BoardInfo A WHERE TENANT_ID = #v_TENANTID# AND PARENTBOARDID = #v_PARENTBOARDID# ), 'top', 99, ( SELECT CASE WHEN MAX(BOARDNO) IS NULL THEN 1 ELSE MAX(BOARDNO) + 1 END FROM TBL_Board_BoardInfo A WHERE TENANT_ID = #v_TENANTID# ), #v_TENANTID#
     		)

